import{c as s}from"./app.8935f5f1.js";const a={},n=s('<ul><li>先检查是否有mysql用户组和mysql用户,没有就添加有就忽略：<code>groups mysql </code></li><li>添加用户组和用户 <code>groupadd mysql &amp;&amp; useradd -r -g mysql mysql</code></li><li>创建数据目录并赋予权限 <code>mkdir -p /data/mysql</code></li><li>修改配置文件 vim /etc/my.cnf （没有就新建）</li></ul><div class="language-cnf ext-cnf"><pre class="language-cnf"><code>[mysqld]\nbind-address=0.0.0.0\nport=3306\nuser=mysql\nbasedir=/usr/local/mysql\ndatadir=/data/mysql\nsocket=/tmp/mysql.sock\nlog-error=/data/mysql/mysql.err\npid-file=/data/mysql/mysql.pid\n#character config\ncharacter_set_server=utf8mb4\nsymbolic-links=0\nexplicit_defaults_for_timestamp=true\n</code></pre></div><ul><li>解压后的<code>mysql-5.7.35-linux.tar.gz</code>文件移动到<code>/usr/local/mysql</code> （文件夹名称修改为mysql不带版本号信息）</li></ul><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> /usr/local/mysql/bin/\n./mysqld --defaults-file<span class="token operator">=</span>/etc/my.cnf --basedir<span class="token operator">=</span>/usr/local/mysql/ --datadir<span class="token operator">=</span>/data/mysql/ --user<span class="token operator">=</span>mysql --initialize\n</code></pre></div><ul><li>查看初始密码 <code>cat /data/mysql/mysql.err</code></li></ul><div class="language-bash ext-sh"><pre class="language-bash"><code>　<span class="token function">cp</span> /usr/local/mysql/support-files/mysql.server /etc/init.d/mysql\n　　<span class="token function">service</span> mysql start\n</code></pre></div><h3 id="修改密码" tabindex="-1"><a class="header-anchor" href="#修改密码" aria-hidden="true">#</a> 修改密码</h3><ol><li>开启免密码登陆 修改<code>my.cnf</code>文件 默认在<code>/etc/my.cnf</code>。</li></ol><p><code>vim /etc/my.cnf</code> 在【mysqld】模块下面添加：<code>skip-grant-tables</code> 保存退出。</p><ol start="2"><li>重启服务，使配置生效 。</li></ol><p><code> service mysql restart</code></p><ol start="3"><li><p>登陆 <code>/usr/local/mysql/bin/mysql -u root -p</code> //不输入密码直接敲回车键</p></li><li><p>刷新规则允许外部访问</p></li></ol><div class="language-sql ext-sql"><pre class="language-sql"><code>　　<span class="token keyword">use</span> mysql 　　　　 <span class="token comment">#选择访问mysql库</span>\n　　<span class="token keyword">update</span> <span class="token keyword">user</span> <span class="token keyword">set</span> host <span class="token operator">=</span> <span class="token string">&#39;%&#39;</span> <span class="token keyword">where</span> <span class="token keyword">user</span> <span class="token operator">=</span> <span class="token string">&#39;root&#39;</span><span class="token punctuation">;</span> 　　　　 <span class="token comment">#使root能再任何host访问</span>\n　　FLUSH <span class="token keyword">PRIVILEGES</span><span class="token punctuation">;</span> 　　 　　 <span class="token comment">#刷新 </span>\n</code></pre></div><ol start="5"><li>修改密码</li></ol><div class="language-sql ext-sql"><pre class="language-sql"><code><span class="token keyword">ALTER</span> <span class="token keyword">USER</span> <span class="token string">&quot;root&quot;</span><span class="token variable">@&quot;%&quot;</span> IDENTIFIED  <span class="token keyword">BY</span> <span class="token string">&quot;1234&quot;</span><span class="token punctuation">;</span>\n\nFLUSH <span class="token keyword">PRIVILEGES</span><span class="token punctuation">;</span> 　　 　　 <span class="token comment">#刷新 </span>\n</code></pre></div>',15);a.render=function(s,a){return n};export{a as default};
